 1→import { readFileSync } from 'fs';
 2→import { dirname, join } from 'path';
 3→import { fileURLToPath } from 'url';
 4→import { HumanMessage, SystemMessage } from '@langchain/core/messages';
 5→import { model } from './model.js';
 6→
 7→const __dirname = dirname(fileURLToPath(import.meta.url));
 8→const SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/generate-system.md'), 'utf8');
 9→
10→/**
11→ * Run the generate stage to produce a SKILL.md.
12→ * @param {object} research - structured research summary from runResearch
13→ * @param {string[]} [validationErrors] - errors from previous validation attempt (for retries)
14→ * @returns {Promise<string>} SKILL.md content
15→ */
16→export async function runGenerate(research, validationErrors = []) {
17→  let userContent = `Generate a complete SKILL.md for the following smart contract research:\n\n${JSON.stringify(research, null, 2)}`;
18→
19→  if (validationErrors.length > 0) {
20→    userContent += `\n\nIMPORTANT: The previous generation attempt failed validation with these errors. Fix all of them:\n${validationErrors.map((e) => `- ${e}`).join('\n')}`;
21→  }
22→
23→  const response = await model.invoke([
24→    new SystemMessage(SYSTEM_PROMPT),
25→    new HumanMessage(userContent),
26→  ]);
27→
28→  return response.content.trim();
29→}
