 55→  chainId: 8453
 56→  generator: "spectopus"
 57→---
 58→
 59→## Overview
 60→Test token.
 61→`;
 62→
 63→describe('runPipeline', () => {
 64→  beforeEach(() => {
 65→    vi.clearAllMocks();
 66→    runResearch.mockResolvedValue(MOCK_RESEARCH);
 67→    runGenerate.mockResolvedValue(VALID_SKILL_MD);
 68→    runValidate.mockResolvedValue({ valid: true, errors: [] });
 69→  });
 70→
 71→  it('runs research → generate → validate in sequence', async () => {
 72→    await runPipeline('skill-1', '0x1234');
 73→
 74→    expect(runResearch).toHaveBeenCalledWith('0x1234');
 75→    expect(runGenerate).toHaveBeenCalledWith(MOCK_RESEARCH);
 76→    expect(runValidate).toHaveBeenCalledWith(VALID_SKILL_MD, []);
 77→  });
 78→
 79→  it('stores the final skill with status ready', async () => {
 80→    await runPipeline('skill-1', '0x1234');
 81→
 82→    expect(putSkill).toHaveBeenCalledWith('skill-1', expect.stringContaining('status: "ready"'));
