 87→    const passResult = { valid: true, errors: [] };
 88→
 89→    runValidate
 90→      .mockResolvedValueOnce(failResult)   // First attempt fails
 91→      .mockResolvedValueOnce(passResult);  // Retry succeeds
 92→
 93→    await runPipeline('skill-1', '0x1234');
 94→
 95→    expect(runGenerate).toHaveBeenCalledTimes(2);
 96→    expect(runValidate).toHaveBeenCalledTimes(2);
 97→    // Second generate call should include the validation errors
