 1→import { readFileSync } from 'fs';
 2→import { dirname, join } from 'path';
 3→import { fileURLToPath } from 'url';
 4→import { createReactAgent } from '@langchain/langgraph/prebuilt';
 5→import { HumanMessage, SystemMessage } from '@langchain/core/messages';
 6→import { model } from './model.js';
 7→import { researchTools } from '../tools/research.js';
 8→
 9→const __dirname = dirname(fileURLToPath(import.meta.url));
10→const SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/research-system.md'), 'utf8');
11→
12→/**
13→ * Run the research stage for a smart contract.
14→ * @param {string} contractAddress
15→ * @returns {Promise<object>} structured research summary
16→ */
17→export async function runResearch(contractAddress) {
18→  const agent = createReactAgent({ llm: model, tools: researchTools });
19→
20→  const result = await agent.invoke({
21→    messages: [
22→      new SystemMessage(SYSTEM_PROMPT),
23→      new HumanMessage(
24→        `Research the smart contract at address ${contractAddress} on Base Mainnet (chainId 8453). Use the tools to fetch the ABI, source code, and detect ERC patterns. Then return a JSON object with your findings.`
25→      ),
26→    ],
27→  });
28→
29→  const messages = result.messages;
30→  const lastMessage = messages[messages.length - 1];
31→  const text = typeof lastMessage.content === 'string' ? lastMessage.content : JSON.stringify(lastMessage.content);
32→
33→  // Extract JSON from the response text
34→  const jsonMatch = text.match(/\{[\s\S]*\}/);
35→  if (!jsonMatch) {
36→    throw new Error(`Research stage did not return valid JSON. Response: ${text.slice(0, 200)}`);
37→  }
38→
39→  const summary = JSON.parse(jsonMatch[0]);
40→  return {
41→    contractAddress,
42→    chainId: 8453,
43→    ...summary,
44→  };
45→}
