62→export async function updateStage(id, stage) {
63→  const content = await getSkill(id);
64→  if (!content) throw new Error(`Skill ${id} not found`);
65→  const updated = content.replace(/^stage: ".+"$/m, `stage: "${stage}"`);
66→  await putSkill(id, updated);
67→}
