 2→import { runResearch } from './research.js';
 3→import { runGenerate } from './generate.js';
 4→import { runValidate } from './validate.js';
 5→
 6→const MAX_RETRIES = 2;
 7→
 8→/**
 9→ * Run the full 3-stage generation pipeline for a skill.
10→ *
11→ * @param {string} skillId - UUID for the skill (S3 key)
12→ * @param {string} contractAddress - contract address to generate skill for
13→ * @param {string} [message] - optional user message / extra context
14→ */
15→export async function runPipeline(skillId, contractAddress, message) {
16→  let retries = 0;
17→
18→  try {
19→    // Stage 1: Research
20→    await updateStage(skillId, 'research');
21→
22→    const research = await runResearch(contractAddress);
23→
24→    if (research.abiAvailable === false) {
25→      throw new Error('Contract ABI is not available — skill generation cannot proceed');
26→    }
27→
28→    // Stage 2: Generate
29→    await updateStage(skillId, 'generate');
30→
31→    let skillContent = await runGenerate(research);
32→
33→    // Stage 3: Validate (with retry loop)
34→    await updateStage(skillId, 'validate');
35→
36→    let validation = await runValidate(skillContent, research.abi || []);
37→
38→    while (!validation.valid && retries < MAX_RETRIES) {
39→      retries++;
40→
41→      // Retry: generate with feedback, then re-validate
42→      await updateStage(skillId, 'generate');
43→      skillContent = await runGenerate(research, validation.errors);
44→
45→      await updateStage(skillId, 'validate');
46→      validation = await runValidate(skillContent, research.abi || []);
47→    }
48→
49→    if (!validation.valid) {
50→      throw new Error(`Validation failed after ${MAX_RETRIES} retries: ${validation.errors.join('; ')}`);
51→    }
52→
53→    // Store final skill with status: ready
54→    const finalContent = markReady(skillContent);
55→    await putSkill(skillId, finalContent);
56→
57→  } catch (err) {
58→    await markFailed(skillId, err.message);
59→    throw err;
60→  }
61→}
62→
63→/**
64→ * Update the status frontmatter field to "ready" in a SKILL.md.
65→ */
66→function markReady(content) {
67→  // If frontmatter exists, add/update status; otherwise prepend it
68→  if (/^---\n/.test(content)) {
69→    if (/^status:/m.test(content)) {
70→      return content.replace(/^status:.*$/m, 'status: "ready"');
71→    }
72→    return content.replace(/^---\n/, '---\nstatus: "ready"\n');
73→  }
74→  return content;
75→}
